public abstract class Specification<T> : ISpecification<T>
{
    public abstract bool IsSatisfiedBy(T entity);
    public abstract string MensagemErro { get; }

    public Specification<T> And(Specification<T> other) => new AndSpecification<T>(this, other);
    public Specification<T> Or(Specification<T> other) => new OrSpecification<T>(this, other);
    public Specification<T> Not() => new NotSpecification<T>(this);
}

// File: Shared/Specifications/Specification.cs
// Namespace: EspacoLuaCheia.Web.Shared.Specifications

public class AndSpecification<T> : Specification<T>
{
    private readonly Specification<T> _left;
    private readonly Specification<T> _right;

    public AndSpecification(Specification<T> left, Specification<T> right)
    {
        _left = left;
        _right = right;
    }

    public override bool IsSatisfiedBy(T entity) =>
        _left.IsSatisfiedBy(entity) && _right.IsSatisfiedBy(entity);

    public override string MensagemErro =>
        !_left.IsSatisfiedBy(default!) ? _left.MensagemErro : _right.MensagemErro;
}

// File: Shared/Specifications/Specification.cs
// Namespace: EspacoLuaCheia.Web.Shared.Specifications

public class OrSpecification<T> : Specification<T>
{
    private readonly Specification<T> _left;
    private readonly Specification<T> _right;

    public OrSpecification(Specification<T> left, Specification<T> right)
    {
        _left = left;
        _right = right;
    }

    public override bool IsSatisfiedBy(T entity) =>
        _left.IsSatisfiedBy(entity) || _right.IsSatisfiedBy(entity);

    public override string MensagemErro => $"{_left.MensagemErro} | {_right.MensagemErro}";
}

// File: Shared/Specifications/Specification.cs
// Namespace: EspacoLuaCheia.Web.Shared.Specifications

public class NotSpecification<T> : Specification<T>
{
    private readonly Specification<T> _inner;

    public NotSpecification(Specification<T> inner) => _inner = inner;

    public override bool IsSatisfiedBy(T entity) => !_inner.IsSatisfiedBy(entity);
    public override string MensagemErro => $"Negacao: {_inner.MensagemErro}";
}

