using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Visitas.Entities;
using EspacoLuaCheia.Web.Features.Visitas.Specifications;
using EspacoLuaCheia.Web.Shared;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

public async Task<Result<Visita>> Agendar(
        long usuarioId,
        DateTime dataHora,
        TipoEvento tipo,
        int qtdPessoas,
        string? descricao,
        long? orcamentoId = null)
    {
        var futuraSpec = new DataVisitaFuturaSpec();
        if (!futuraSpec.IsSatisfiedBy(dataHora))
            return Result.Fail<Visita>(futuraSpec.MensagemErro);

        var horarioSpec = new DataVisitaDentroHorarioComercialSpec();
        if (!horarioSpec.IsSatisfiedBy(dataHora))
            return Result.Fail<Visita>(horarioSpec.MensagemErro);

        var agora = DateTime.UtcNow;

        var visita = new Visita
        {
            UsuarioId = usuarioId,
            OrcamentoId = orcamentoId,
            TipoEvento = tipo,
            QuantidadePessoas = qtdPessoas,
            Descricao = descricao?.Trim(),
            DataHoraVisita = dataHora,
            CriadoEm = agora,
            AtualizadoEm = agora
        };

        db.Visitas.Add(visita);
        await db.SaveChangesAsync();

        return Result.Ok(visita);
    }

