using EspacoLuaCheia.Web.Shared.Specifications;

/// <summary>
/// Validates that the visit is scheduled between 08:00 and 18:00 (commercial hours).
/// </summary>
public class DataVisitaDentroHorarioComercialSpec : Specification<DateTime>
{
    private const int HoraInicio = 8;
    private const int HoraFim = 18;

    public override bool IsSatisfiedBy(DateTime dataHora) =>
        dataHora.Hour >= HoraInicio && dataHora.Hour < HoraFim;

    public override string MensagemErro =>
        $"A visita deve ser agendada dentro do horário comercial ({HoraInicio}h às {HoraFim}h).";
}

