// Class: TabelaPrecoService
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Dtos;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Entities;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Specifications;
using EspacoLuaCheia.Web.Shared;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

// -------------------------------------------------------------------------
    // Commands
    // -------------------------------------------------------------------------

    public async Task<Result> CriarTabela(TabelaPreco tabela)
    {
        // Validate vigencia
        var vigenciaSpec = new TabelaVigenciaValidaSpec();
        if (!vigenciaSpec.IsSatisfiedBy(tabela))
            return Result.Fail(vigenciaSpec.MensagemErro);

        // Validate faixas
        foreach (var faixa in tabela.Faixas)
        {
            var qtdSpec = new FaixaQuantidadePositivaSpec();
            if (!qtdSpec.IsSatisfiedBy(faixa))
                return Result.Fail(qtdSpec.MensagemErro);

            var valorSpec = new FaixaValorPositivoSpec();
            if (!valorSpec.IsSatisfiedBy(faixa))
                return Result.Fail(valorSpec.MensagemErro);
        }

        // Validate no overlap with existing active tabelas (external data resolved before spec)
        var existeSobreposicao = await ExisteSobreposicaoVigencia(tabela.TipoEvento, tabela.VigenciaInicio, tabela.VigenciaFim, excludeId: null);
        var sobreposicaoSpec = new TabelaSemSobreposicaoVigenciaSpec(existeSobreposicao);
        if (!sobreposicaoSpec.IsSatisfiedBy(tabela))
            return Result.Fail(sobreposicaoSpec.MensagemErro);

        // Validate must have at least one faixa
        var faixasSpec = new TabelaPossuiFaixasSpec();
        if (!faixasSpec.IsSatisfiedBy(tabela))
            return Result.Fail(faixasSpec.MensagemErro);

        tabela.CriadoEm = DateTime.UtcNow;
        tabela.AtualizadoEm = DateTime.UtcNow;

        _db.TabelasPreco.Add(tabela);
        await _db.SaveChangesAsync();

        return Result.Ok();
    }

// File: Features/TabelaPrecos/Services/TabelaPrecoService.cs
// Namespace: EspacoLuaCheia.Web.Features.TabelaPrecos.Services
// Class: TabelaPrecoService
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Dtos;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Entities;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Specifications;
using EspacoLuaCheia.Web.Shared;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

public async Task<Result> EditarTabela(TabelaPreco tabela)
    {
        var existente = await _db.TabelasPreco
            .Include(t => t.Faixas)
            .Include(t => t.OpcoesSuite)
            .FirstOrDefaultAsync(t => t.Id == tabela.Id);

        if (existente is null)
            return Result.Fail("Tabela de precos nao encontrada.");

        // Validate vigencia
        var vigenciaSpec = new TabelaVigenciaValidaSpec();
        if (!vigenciaSpec.IsSatisfiedBy(tabela))
            return Result.Fail(vigenciaSpec.MensagemErro);

        // Validate faixas
        foreach (var faixa in tabela.Faixas)
        {
            var qtdSpec = new FaixaQuantidadePositivaSpec();
            if (!qtdSpec.IsSatisfiedBy(faixa))
                return Result.Fail(qtdSpec.MensagemErro);

            var valorSpec = new FaixaValorPositivoSpec();
            if (!valorSpec.IsSatisfiedBy(faixa))
                return Result.Fail(valorSpec.MensagemErro);
        }

        // Validate overlap excluding self
        var existeSobreposicao = await ExisteSobreposicaoVigencia(tabela.TipoEvento, tabela.VigenciaInicio, tabela.VigenciaFim, excludeId: tabela.Id);
        var sobreposicaoSpec = new TabelaSemSobreposicaoVigenciaSpec(existeSobreposicao);
        if (!sobreposicaoSpec.IsSatisfiedBy(tabela))
            return Result.Fail(sobreposicaoSpec.MensagemErro);

        // Validate must have at least one faixa
        var faixasSpec = new TabelaPossuiFaixasSpec();
        if (!faixasSpec.IsSatisfiedBy(tabela))
            return Result.Fail(faixasSpec.MensagemErro);

        // Apply scalar updates
        existente.Nome = tabela.Nome;
        existente.TipoEvento = tabela.TipoEvento;
        existente.VigenciaInicio = tabela.VigenciaInicio;
        existente.VigenciaFim = tabela.VigenciaFim;
        existente.PercentualSinal = tabela.PercentualSinal;
        existente.DiasAntecedenciaSaldo = tabela.DiasAntecedenciaSaldo;
        existente.Descricao = tabela.Descricao;
        existente.Ativa = tabela.Ativa;
        existente.AtualizadoEm = DateTime.UtcNow;

        // Replace faixas: remove all then re-add
        _db.FaixasPreco.RemoveRange(existente.Faixas);
        foreach (var faixa in tabela.Faixas)
        {
            faixa.Id = 0;
            faixa.TabelaPrecoId = existente.Id;
            _db.FaixasPreco.Add(faixa);
        }

        // Replace opcoes suite: remove all then re-add
        _db.OpcoesSuite.RemoveRange(existente.OpcoesSuite);
        foreach (var opcao in tabela.OpcoesSuite)
        {
            opcao.Id = 0;
            opcao.TabelaPrecoId = existente.Id;
            _db.OpcoesSuite.Add(opcao);
        }

        await _db.SaveChangesAsync();
        return Result.Ok();
    }

