    public async Task<TabelaPrecoResumoDto?> BuscarTabelaVigente(TipoEvento tipoEvento, DateOnly data)
    {
        var tabela = await _db.TabelasPreco
            .Include(t => t.Faixas.OrderBy(f => f.OrdemExibicao))
            .Include(t => t.OpcoesSuite)
            .Where(t =>
                t.Ativa &&
                t.TipoEvento == tipoEvento &&
                t.VigenciaInicio <= data &&
                t.VigenciaFim >= data)
            .FirstOrDefaultAsync();

        if (tabela is null)
            return null;

        return ToResumoDto(tabela);
    }

