    private async Task<bool> ExisteSobreposicaoVigencia(TipoEvento tipoEvento, DateOnly inicio, DateOnly fim, long? excludeId)
    {
        return await _db.TabelasPreco.AnyAsync(t =>
            t.Ativa &&
            t.TipoEvento == tipoEvento &&
            (excludeId == null || t.Id != excludeId) &&
            t.VigenciaInicio < fim &&
            t.VigenciaFim > inicio);
    }

