using System.Globalization;
using EspacoLuaCheia.Web.Features.Pagamentos.Services;
using EspacoLuaCheia.Web.Features.Reservas.Dtos;

public class DashboardService(
    ReservaService reservaService,
    PagamentoService pagamentoService)
{
    private static readonly CultureInfo BrCulture = new("pt-BR");
    private const int MesesAntes = 3;
    private const int MesesDepois = 3;

    public async Task<DashboardGraficoDto> ObterGraficoReservasXRecebimentos()
    {
        var hoje = DateOnly.FromDateTime(DateTime.Today);
        var referencia = new DateOnly(hoje.Year, hoje.Month, 1);

        var inicio = referencia.AddMonths(-MesesAntes);
        var fimMes = referencia.AddMonths(MesesDepois);
        var fim = fimMes.AddMonths(1).AddDays(-1);

        var reservas = await reservaService.ObterValoresPorMes(inicio, fim);
        var recebidos = await pagamentoService.ObterRecebidosPorMes(inicio, fim);

        var mapReservas = reservas.ToDictionary(r => (r.Ano, r.Mes), r => r.ValorTotal);
        var mapRecebidos = recebidos.ToDictionary(r => (r.Ano, r.Mes), r => r.ValorTotal);

        var pontos = new List<DashboardGraficoMensalDto>(MesesAntes + MesesDepois + 1);
        for (var i = -MesesAntes; i <= MesesDepois; i++)
        {
            var mesRef = referencia.AddMonths(i);
            var chave = (mesRef.Year, mesRef.Month);

            mapReservas.TryGetValue(chave, out var valorReservas);
            mapRecebidos.TryGetValue(chave, out var valorRecebido);

            pontos.Add(new DashboardGraficoMensalDto(
                mesRef.Year,
                mesRef.Month,
                MontarLabel(mesRef),
                valorReservas,
                valorRecebido));
        }

        return new DashboardGraficoDto(pontos);
    }

    private static string MontarLabel(DateOnly mes)
    {
        var nomeMes = BrCulture.DateTimeFormat.GetAbbreviatedMonthName(mes.Month).TrimEnd('.').ToLower(BrCulture);
        return $"{nomeMes}/{mes.Year}";
    }
}

