public async Task<Result<Reserva>> CriarReserva(
        long contratoId,
        long usuarioId,
        DateOnly dataEvento,
        int qtdConvidados,
        TipoEvento tipo,
        decimal valorTotal,
        int percentualSinal)
    {
        // Resolve dependency, then pass result to spec
        var existeReserva = await db.Reservas
            .AnyAsync(r => r.DataEvento == dataEvento && r.Status != StatusReserva.Cancelada);

        // Use a dummy reserva for the spec check
        var specReserva = new Reserva { DataEvento = dataEvento };
        var disponivelSpec = new DataEventoDisponivelSpec(existeReserva);
        if (!disponivelSpec.IsSatisfiedBy(specReserva))
            return Result.Fail<Reserva>(disponivelSpec.MensagemErro);

        var valorSinal = Math.Round(valorTotal * (percentualSinal / 100m), 2);

        var agora = DateTime.UtcNow;
        var reserva = new Reserva
        {
            ContratoId = contratoId,
            UsuarioId = usuarioId,
            Status = StatusReserva.PendenteAssinatura,
            DataEvento = dataEvento,
            QuantidadeConvidados = qtdConvidados,
            TipoEvento = tipo,
            ValorTotal = valorTotal,
            ValorSinal = valorSinal,
            ValorPago = 0m,
            CriadoEm = agora,
            AtualizadoEm = agora
        };

        db.Reservas.Add(reserva);
        await db.SaveChangesAsync();

        return Result.Ok(reserva);
    }

