public async Task<Result> Cancelar(long reservaId)
    {
        var reserva = await db.Reservas.FindAsync(reservaId);
        if (reserva is null)
            return Result.Fail("Reserva nao encontrada.");

        var podeSpec = new PodeCancelarReservaSpec();
        if (!podeSpec.IsSatisfiedBy(reserva))
            return Result.Fail(podeSpec.MensagemErro);

        var multaSpec = new CancelamentoComMultaSpec();
        var temMulta = multaSpec.IsSatisfiedBy(reserva);

        reserva.Status = StatusReserva.Cancelada;
        reserva.AtualizadoEm = DateTime.UtcNow;
        await db.SaveChangesAsync();

        return temMulta
            ? Result.Fail($"Reserva cancelada. {multaSpec.MensagemErro}")
            : Result.Ok();
    }

