public async Task<Result<Pagamento>> Criar(
        long reservaId,
        decimal valor,
        TipoPagamento tipo,
        DateOnly dataVencimento,
        string? comprovante = null,
        string metodoPagamento = "PIX")
    {
        var pagamento = new Pagamento
        {
            ReservaId = reservaId,
            Valor = valor,
            Tipo = tipo,
            MetodoPagamento = metodoPagamento,
            DataVencimento = dataVencimento,
            Confirmado = false,
            Comprovante = comprovante,
            CriadoEm = DateTime.UtcNow
        };

        var valorPositivoSpec = new ValorPagamentoPositivoSpec();
        if (!valorPositivoSpec.IsSatisfiedBy(pagamento))
            return Result.Fail<Pagamento>(valorPositivoSpec.MensagemErro);

        var jaExisteConfirmado = await db.Pagamentos
            .AnyAsync(p => p.ReservaId == reservaId && p.Tipo == tipo && p.Confirmado);

        var naoDuplicadoSpec = new PagamentoNaoDuplicadoSpec(jaExisteConfirmado);
        if (!naoDuplicadoSpec.IsSatisfiedBy(pagamento))
            return Result.Fail<Pagamento>(naoDuplicadoSpec.MensagemErro);

        db.Pagamentos.Add(pagamento);
        await db.SaveChangesAsync();

        return Result.Ok(pagamento);
    }

