using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Pagamentos.Dtos;
using EspacoLuaCheia.Web.Features.Pagamentos.Entities;
using EspacoLuaCheia.Web.Features.Pagamentos.Specifications;
using EspacoLuaCheia.Web.Features.Reservas.Services;
using EspacoLuaCheia.Web.Shared;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

public async Task<Result> Confirmar(long pagamentoId)
    {
        var pagamento = await db.Pagamentos.FindAsync(pagamentoId);
        if (pagamento is null)
            return Result.Fail("Pagamento nao encontrado.");

        var valorPositivoSpec = new ValorPagamentoPositivoSpec();
        if (!valorPositivoSpec.IsSatisfiedBy(pagamento))
            return Result.Fail(valorPositivoSpec.MensagemErro);

        pagamento.Confirmado = true;
        pagamento.DataPagamento = DateOnly.FromDateTime(DateTime.Today);

        // Update the linked Reserva
        var reserva = await db.Reservas.FindAsync(pagamento.ReservaId);
        if (reserva is not null)
        {
            reserva.ValorPago += pagamento.Valor;
            reserva.AtualizadoEm = DateTime.UtcNow;

            if (pagamento.Tipo == TipoPagamento.Sinal)
            {
                // Transition: PendenteSinal -> SinalPago
                var result = await reservaService.RegistrarSinal(reserva.Id);
                // Ignore failure here — status may already have been updated
            }
            else if (pagamento.Tipo == TipoPagamento.SaldoRestante || reserva.ValorPago >= reserva.ValorTotal)
            {
                // Transition: SinalPago -> Confirmada
                var result = await reservaService.ConfirmarReserva(reserva.Id);
                // Ignore failure here — status may already have been updated
            }
        }

        await db.SaveChangesAsync();

        return Result.Ok();
    }

