using Microsoft.EntityFrameworkCore;

public async Task<IReadOnlyList<PagamentoRecebidoMensalDto>> ObterRecebidosPorMes(DateOnly inicio, DateOnly fim)
    {
        var pagamentos = await db.Pagamentos
            .Where(p => p.Confirmado && p.DataPagamento != null)
            .Where(p => p.DataPagamento >= inicio && p.DataPagamento <= fim)
            .Select(p => new { Data = p.DataPagamento!.Value, p.Valor })
            .ToListAsync();

        return pagamentos
            .GroupBy(p => new { p.Data.Year, p.Data.Month })
            .Select(g => new PagamentoRecebidoMensalDto(
                g.Key.Year,
                g.Key.Month,
                g.Sum(p => p.Valor)))
            .ToList();
    }

