// Class: OrcamentoService
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Orcamentos.Entities;
using EspacoLuaCheia.Web.Features.Orcamentos.Specifications;
using EspacoLuaCheia.Web.Features.TabelaPrecos.Services;
using EspacoLuaCheia.Web.Shared;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

public async Task<Result<Orcamento>> CriarOrcamento(
        long usuarioId,
        TipoEvento tipo,
        int qtdPessoas,
        DateOnly dataPrevista,
        int qtdSuites = 0)
    {
        // Step 1: fetch the active price table via the TabelaPrecos context service
        var tabela = await tabelaPrecoService.BuscarTabelaVigente(tipo, dataPrevista);

        // Step 2: validate that a vigente table exists
        var tabelaExisteSpec = new TabelaVigenteExisteSpec(tabela is not null);
        if (!tabelaExisteSpec.IsSatisfiedBy(tabela is not null))
            return Result.Fail<Orcamento>(tabelaExisteSpec.MensagemErro);

        // Step 3: determine the maximum allowed persons (largest faixa) and validate
        int maximoPermitido = tabela!.Faixas.Count > 0
            ? tabela.Faixas.Max(f => f.QuantidadeMaxima)
            : 0;

        var qtdPessoasSpec = new QuantidadePessoasDentroFaixaSpec(maximoPermitido);
        if (!qtdPessoasSpec.IsSatisfiedBy(qtdPessoas))
            return Result.Fail<Orcamento>(qtdPessoasSpec.MensagemErro);

        // Step 4: find the correct faixa — smallest where QuantidadeMaxima >= qtdPessoas
        var faixa = tabela.Faixas
            .Where(f => f.QuantidadeMaxima >= qtdPessoas)
            .OrderBy(f => f.QuantidadeMaxima)
            .FirstOrDefault();

        if (faixa is null)
            return Result.Fail<Orcamento>($"Quantidade de pessoas excede o maximo permitido na tabela vigente ({maximoPermitido}).");

        // Step 5: calculate suites if applicable
        decimal valorSuites = 0m;

        if (qtdSuites > 0)
        {
            var opcaoSuite = tabela.OpcoesSuite.FirstOrDefault();
            int maxSuites = opcaoSuite?.QuantidadeMaxima ?? 0;

            var suitesSpec = new QuantidadeSuitesDentroLimiteSpec(maxSuites);
            if (!suitesSpec.IsSatisfiedBy(qtdSuites))
                return Result.Fail<Orcamento>(suitesSpec.MensagemErro);

            if (opcaoSuite is not null)
                valorSuites = qtdSuites * opcaoSuite.ValorUnitario;
        }

        // Step 6: snapshot values into Orcamento entity and persist
        var agora = DateTime.UtcNow;
        var orcamento = new Orcamento
        {
            UsuarioId = usuarioId,
            TabelaPrecoId = tabela.Id,
            FaixaPrecoId = faixa.Id,
            TipoEvento = tipo,
            QuantidadePessoas = qtdPessoas,
            ValorBase = faixa.Valor,
            ValorSuites = valorSuites,
            QuantidadeSuites = qtdSuites,
            ValorTotal = faixa.Valor + valorSuites,
            ValidoAte = DateOnly.FromDateTime(DateTime.Today.AddDays(DiasValidadeOrcamento)),
            CriadoEm = agora,
            AtualizadoEm = agora
        };

        db.Orcamentos.Add(orcamento);
        await db.SaveChangesAsync();

        return Result.Ok(orcamento);
    }

