using System.Text.Json;
using EspacoLuaCheia.Web.Features.Leads.Integrations.Dtos;

public async Task<GetBase64MediaResponse> GetBase64FromMediaMessage(string messageKeyId)
    {
        var client = CreateClient();
        var body = new StringContent(
            JsonSerializer.Serialize(new
            {
                message = new { key = new { id = messageKeyId } },
                convertToMp4 = false
            }),
            System.Text.Encoding.UTF8, "application/json");
        var response = await client.PostAsync($"/chat/getBase64FromMediaMessage/{InstanceName}", body);
        response.EnsureSuccessStatusCode();
        var json = await response.Content.ReadAsStringAsync();
        return JsonSerializer.Deserialize<GetBase64MediaResponse>(json, JsonOptions) ?? new();
    }

