private static string ObterExtensao(string mimeType, string fallback)
    {
        return mimeType switch
        {
            "image/jpeg" => ".jpg",
            "image/png" => ".png",
            "image/webp" => ".webp",
            "image/gif" => ".gif",
            "audio/ogg" => ".ogg",
            "audio/mpeg" => ".mp3",
            "audio/mp4" => ".m4a",
            "video/mp4" => ".mp4",
            "application/pdf" => ".pdf",
            _ => Path.GetExtension(fallback) is { Length: > 0 } ext ? ext : ".bin"
        };
    }

