public async Task<Result<long>> Converter(long id)
    {
        var lead = await db.Leads.FindAsync(id);
        if (lead is null)
            return Result.Fail<long>("Lead não encontrado.");

        var spec = new LeadConversavelSpec();
        if (!spec.IsSatisfiedBy(lead))
            return Result.Fail<long>(spec.MensagemErro);

        var resultUsuario = await clienteService.Criar(lead.NomeReal!, lead.Celular);
        if (!resultUsuario.Sucesso)
            return Result.Fail<long>(resultUsuario.Erro!);

        var usuario = resultUsuario.Valor!;
        lead.UsuarioId = usuario.Id;
        lead.Status = StatusLead.Convertido;
        lead.AtualizadoEm = DateTime.UtcNow;
        await db.SaveChangesAsync();

        return Result.Ok(usuario.Id);
    }

