// Namespace: EspacoLuaCheia.Web.Features.Leads.Services
// Class: WhatsAppWebhookHandler
using System.Text.Json;
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Leads.Entities;
using EspacoLuaCheia.Web.Features.Leads.Enums;
using EspacoLuaCheia.Web.Features.Leads.Specifications;
using Microsoft.AspNetCore.Hosting;
using Microsoft.EntityFrameworkCore;

private static (TipoMensagem Tipo, string? Texto, string? MimeType, string? FileName) ExtrairConteudo(JsonElement data)
    {
        if (!data.TryGetProperty("message", out var message))
            return (TipoMensagem.Desconhecido, null, null, null);

        if (message.TryGetProperty("conversation", out var conv) && conv.ValueKind == JsonValueKind.String)
            return (TipoMensagem.Texto, conv.GetString(), null, null);

        if (message.TryGetProperty("imageMessage", out var imgMsg) && imgMsg.ValueKind != JsonValueKind.Null)
        {
            var mime = imgMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "image/jpeg";
            return (TipoMensagem.Imagem, null, mime, null);
        }

        if (message.TryGetProperty("audioMessage", out var audioMsg) && audioMsg.ValueKind != JsonValueKind.Null)
        {
            var mime = audioMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "audio/ogg";
            return (TipoMensagem.Audio, null, mime, null);
        }

        if (message.TryGetProperty("documentMessage", out var docMsg) && docMsg.ValueKind != JsonValueKind.Null)
        {
            var mime = docMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "application/octet-stream";
            var fn = docMsg.TryGetProperty("fileName", out var fnProp) ? fnProp.GetString() : null;
            return (TipoMensagem.Documento, null, mime, fn);
        }

        if (message.TryGetProperty("videoMessage", out var videoMsg) && videoMsg.ValueKind != JsonValueKind.Null)
        {
            var mime = videoMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "video/mp4";
            return (TipoMensagem.Video, null, mime, null);
        }

        if (message.TryGetProperty("stickerMessage", out var stickerMsg) && stickerMsg.ValueKind != JsonValueKind.Null)
        {
            var mime = stickerMsg.TryGetProperty("mimetype", out var mt) ? mt.GetString() : "image/webp";
            return (TipoMensagem.Sticker, null, mime, null);
        }

        return (TipoMensagem.Desconhecido, null, null, null);
    }

