// Namespace: EspacoLuaCheia.Web.Features.Contratos.Services
// Class: ContratoPdfService
using EspacoLuaCheia.Web.Features.Contratos.Entities;
using EspacoLuaCheia.Web.Features.Contratos.Specifications;
using EspacoLuaCheia.Web.Features.Contratos.Templates;
using EspacoLuaCheia.Web.Shared.Enums;
using QuestPDF.Fluent;
using QuestPDF.Helpers;
using QuestPDF.Infrastructure;
using System.Globalization;

public async Task<(byte[] Bytes, string FileName)?> GerarAsync(long contratoId)
    {
        var contrato = await contratos.ObterPorId(contratoId);
        if (contrato is null) return null;

        var clausulas = MontarClausulas(contrato);
        var nomeArquivo = new NomeArquivoContratoSpec().Resolve(
            contrato.NomeCompleto,
            TipoEventoTexto(contrato.TipoEvento),
            contrato.DataEvento);

        var logoPath = Path.Combine(env.WebRootPath, "images", "espaco-lua-cheia-logo-transparente.png");
        var bytes = Document.Create(doc => Compor(doc, contrato, clausulas, logoPath)).GeneratePdf();
        return (bytes, nomeArquivo);
    }

