using QuestPDF.Fluent;
using QuestPDF.Helpers;
using QuestPDF.Infrastructure;
using System.Globalization;

private static IReadOnlyList<ClausulaRenderizada> MontarClausulas(Contrato c)
    {
        var basePadrao = ClausulasBaseTemplate.Para(c);

        var adicionais = c.ClausulasAdicionais.ToList();
        if (c.IncluirClausulaLimpeza)
            adicionais.Add(ClausulasBaseTemplate.MaterializarLimpeza(c));

        return new RenumeracaoClausulasContratoSpec().Resolve(basePadrao, adicionais);
    }

