// Namespace: EspacoLuaCheia.Web.Features.Contratos.Services
// Class: ContratoPdfService
using EspacoLuaCheia.Web.Features.Contratos.Entities;
using EspacoLuaCheia.Web.Features.Contratos.Specifications;
using EspacoLuaCheia.Web.Features.Contratos.Templates;
using EspacoLuaCheia.Web.Shared.Enums;
using QuestPDF.Fluent;
using QuestPDF.Helpers;
using QuestPDF.Infrastructure;
using System.Globalization;

private static void Compor(IDocumentContainer doc, Contrato c, IReadOnlyList<ClausulaRenderizada> clausulas, string logoPath)
    {
        doc.Page(page =>
        {
            page.Size(PageSizes.A4);
            page.MarginHorizontal(50);
            page.MarginVertical(40);
            page.DefaultTextStyle(t => t.FontFamily(Fonts.Calibri).FontSize(10).LineHeight(1.5f));

            page.Header().Element(h => Cabecalho(h, c, logoPath));
            page.Content().Element(content => Conteudo(content, c, clausulas));
            page.Footer().AlignCenter().Text(t =>
            {
                t.CurrentPageNumber();
                t.Span(" / ");
                t.TotalPages();
            });
        });
    }

