            ? "CONTRATO DE LOCAÇÃO DE ESPAÇO PARA CASAMENTO"
            : "CONTRATO DE LOCAÇÃO DE ESPAÇO PARA FESTA";

        container.PaddingBottom(12).Column(col =>
        {
            if (File.Exists(logoPath))
                col.Item().AlignCenter().MaxHeight(80).Image(logoPath).FitHeight();

            col.Item().PaddingTop(6).AlignCenter().Text(titulo).FontSize(13).Bold();
            col.Item().PaddingTop(4).LineHorizontal(1.5f).LineColor(Colors.Grey.Darken2);
        });
