private static void Conteudo(IContainer container, Contrato c, IReadOnlyList<ClausulaRenderizada> clausulas)
    {
        container.Column(col =>
        {
            col.Spacing(10);

            col.Item().Element(e => SecaoLocador(e));
            col.Item().Element(e => SecaoLocatario(e, c));
            col.Item().Element(e => SecaoEvento(e, c));

            foreach (var cl in clausulas)
            {
                col.Item().Element(e => RenderClausula(e, cl));
            }

            col.Item().PaddingTop(20).Element(e => Assinaturas(e, c));
        });
    }

