// Namespace: EspacoLuaCheia.Web.Features.Contratos.Services
// Class: ContratoPdfService
using EspacoLuaCheia.Web.Features.Contratos.Entities;
using EspacoLuaCheia.Web.Features.Contratos.Specifications;
using EspacoLuaCheia.Web.Features.Contratos.Templates;
using EspacoLuaCheia.Web.Shared.Enums;
using QuestPDF.Fluent;
using QuestPDF.Helpers;
using QuestPDF.Infrastructure;
using System.Globalization;

/// <summary>
    /// Renderiza o texto plano da cláusula com suporte a:
    /// - Parágrafos separados por linha em branco
    /// - Itens de lista com "- texto"
    /// - Itens com letras "a) texto", "b) texto"
    /// </summary>
    private static void RenderTextoClausula(ColumnDescriptor col, string texto)
    {
        var linhas = texto.Split('\n');
        foreach (var linha in linhas)
        {
            if (string.IsNullOrWhiteSpace(linha))
            {
                col.Item().Text(""); // espaço entre parágrafos
                continue;
            }

            var trimmed = linha.TrimStart();

            if (trimmed.StartsWith("- "))
            {
                // item de lista com marcador
                col.Item().Row(row =>
                {
                    row.ConstantItem(14).Text("•").FontSize(10);
                    row.RelativeItem().Text(trimmed[2..]);
                });
            }
            else if (trimmed.Length > 2 && char.IsLower(trimmed[0]) && trimmed[1] == ')' && trimmed[2] == ' ')
            {
                // item com letra: a) b) c) ...
                col.Item().Row(row =>
                {
                    row.ConstantItem(18).Text(trimmed[..2]).FontSize(10);
                    row.RelativeItem().Text(trimmed[3..]);
                });
            }
            else
            {
                col.Item().Text(linha);
            }
        }
    }

