private static void Assinaturas(IContainer container, Contrato c)
    {
        var dataAssinatura = c.CriadoEm.ToLocalTime();
        var dataExtenso = $"{dataAssinatura.Day} de {_meses[dataAssinatura.Month]} de {dataAssinatura.Year}";

        container.Column(col =>
