private static string FormatarHorario(string? valor, string fallback)
    {
        if (string.IsNullOrWhiteSpace(valor)) return fallback;
        var cleaned = valor.Replace("h", ":").Replace("H", ":");
        if (TimeOnly.TryParse(cleaned, out var time))
            return time.ToString("HH'h'mm");
        return TimeOnly.TryParse(valor, out time) ? time.ToString("HH'h'mm") : valor;
    }

