        string? rg,
        string cpf,
        string? email,
        string? endereco,
        DateOnly dataEvento,
        string? horarioPrevisto,
        string? horarioTermino,
        int quantidadeConvidados,
        TipoEvento tipoEvento,
        decimal valorTotal,
        int percentualSinal = 50,
        int diasAntecedenciaSaldo = 7)
    {
        var contrato = new Contrato
        {
            UsuarioId = usuarioId,
            OrcamentoId = orcamentoId,
            NomeCompleto = nomeCompleto,
            RG = rg,
            CPF = cpf,
            Email = email,
            Endereco = endereco,
            DataEvento = dataEvento,
            HorarioPrevisto = horarioPrevisto,
            HorarioTermino = string.IsNullOrWhiteSpace(horarioTermino) ? "00h" : horarioTermino,
            QuantidadeConvidados = quantidadeConvidados,
            TipoEvento = tipoEvento,
            ValorTotal = valorTotal,
            PercentualSinal = percentualSinal,
            DiasAntecedenciaSaldo = diasAntecedenciaSaldo,
            CriadoEm = DateTime.UtcNow,
            AtualizadoEm = DateTime.UtcNow
        };

        var dadosCompletosSpec = new DadosContratoPfCompletosSpec();
        if (!dadosCompletosSpec.IsSatisfiedBy(contrato))
            return Result.Fail<Contrato>(dadosCompletosSpec.MensagemErro);

        var cpfValidoSpec = new CpfValidoSpec();
        if (!cpfValidoSpec.IsSatisfiedBy(contrato))
