public async Task<Result> AtualizarTextoClausula(long contratoId, string chaveClausula, string? texto)
    {
        var contrato = await db.Contratos.FindAsync(contratoId);
        if (contrato is null)
            return Result.Fail("Contrato nao encontrado.");

        if (string.IsNullOrWhiteSpace(chaveClausula))
            return Result.Fail("Chave da clausula e obrigatoria.");

        // Reatribui o dicionario para o EF detectar a mudanca (value converter + jsonb).
        var novo = new Dictionary<string, string>(contrato.TextosCustomizadosClausulas);
        if (string.IsNullOrWhiteSpace(texto))
            novo.Remove(chaveClausula);
        else
            novo[chaveClausula] = texto.Trim();

        contrato.TextosCustomizadosClausulas = novo;
        contrato.AtualizadoEm = DateTime.UtcNow;

        await db.SaveChangesAsync();
        return Result.Ok();
    }

