// Namespace: EspacoLuaCheia.Web.Features.Contratos.Specifications
using System.Globalization;
using System.Text;
using System.Text.RegularExpressions;

/// <summary>
/// Calcula o nome do arquivo PDF do contrato no padrao
/// contrato_locacao_espaco_lua_cheia_{primeiroNome}_{tipoEvento}_{ddMMyyyy}.pdf
/// (tudo minusculo, sem acentos, alfanumericos -> '-').
/// </summary>
public class NomeArquivoContratoSpec
{
    public string Resolve(string nomeCompleto, string tipoEventoDisplay, DateOnly dataEvento)
    {
        var primeiroNome = Sanitizar(PrimeiraPalavra(nomeCompleto));
        var tipo = Sanitizar(tipoEventoDisplay);
        var data = dataEvento.ToString("ddMMyyyy");
        return $"contrato_locacao_espaco_lua_cheia_{primeiroNome}_{tipo}_{data}.pdf";
    }

    private static string PrimeiraPalavra(string texto)
    {
        if (string.IsNullOrWhiteSpace(texto)) return "cliente";
        var partes = texto.Split([' ', '\t'], StringSplitOptions.RemoveEmptyEntries);
        return partes.Length == 0 ? "cliente" : partes[0];
    }

    private static string Sanitizar(string texto)
    {
        if (string.IsNullOrWhiteSpace(texto)) return "indefinido";

        var normalizado = texto.Normalize(NormalizationForm.FormD);
        var sb = new StringBuilder(normalizado.Length);
        foreach (var c in normalizado)
        {
            if (CharUnicodeInfo.GetUnicodeCategory(c) != UnicodeCategory.NonSpacingMark)
                sb.Append(c);
        }

        var semAcento = sb.ToString().ToLowerInvariant();
        var saneado = Regex.Replace(semAcento, @"[^a-z0-9]+", "-").Trim('-');
        return string.IsNullOrEmpty(saneado) ? "indefinido" : saneado;
    }
}

