// Namespace: EspacoLuaCheia.Web.Features.Contratos.Specifications
using EspacoLuaCheia.Web.Features.Contratos.Entities;

/// <summary>
/// Intercala clausulas base + adicionais (incluindo a de limpeza, materializada pelo Service)
/// e produz numeracao sequencial 1..N. Adicionais com mesma posicao de uma base
/// vem ANTES da base. Empate entre adicionais: ordena por Id (ordem de criacao).
/// </summary>
public class RenumeracaoClausulasContratoSpec
{
    public IReadOnlyList<ClausulaRenderizada> Resolve(
        IReadOnlyList<ClausulaBase> clausulasBase,
        IReadOnlyList<ClausulaAdicional> adicionais)
    {
        var resultado = new List<ClausulaRenderizada>();

        // Adicionais agrupadas por Posicao (1-based no contrato final).
        var ordenadas = adicionais
            .OrderBy(a => a.Posicao)
            .ThenBy(a => a.Id)
            .ToList();

        // Ponteiro nas adicionais.
        var idxAdicional = 0;
        var numero = 1;

        for (var i = 0; i < clausulasBase.Count; i++)
        {
            var posicaoBaseAtual = i + 1;

            // Drena adicionais cuja posicao desejada eh <= posicaoBaseAtual.
            // Adicional com posicao N = vir antes da clausula que ocuparia posicao N.
            while (idxAdicional < ordenadas.Count && ordenadas[idxAdicional].Posicao <= posicaoBaseAtual)
            {
                var add = ordenadas[idxAdicional++];
                resultado.Add(new ClausulaRenderizada(numero++, add.Titulo, add.Texto));
            }

            var b = clausulasBase[i];
            resultado.Add(new ClausulaRenderizada(numero++, b.Titulo, b.Texto));
        }

        // Resto das adicionais vai para o final.
        while (idxAdicional < ordenadas.Count)
        {
            var add = ordenadas[idxAdicional++];
            resultado.Add(new ClausulaRenderizada(numero++, add.Titulo, add.Texto));
        }

        return resultado;
    }
}

