private static IReadOnlyList<ClausulaBase> Festa(Contrato c)
    {
        var valorTotal = c.ValorTotal.ToString("C", _ptBr);
        var valorSinal = (c.ValorTotal * c.PercentualSinal / 100m).ToString("C", _ptBr);
        var dataLimite = c.DataEvento.AddDays(-c.DiasAntecedenciaSaldo).ToString("dd/MM/yyyy");
        var diasTexto = c.DiasAntecedenciaSaldo == 1 ? "1 (um) dia" : $"{c.DiasAntecedenciaSaldo} ({PorExtenso(c.DiasAntecedenciaSaldo)}) dias";

        // Financeiro: texto dinamico (nao customizavel — e form estruturado).
        var textoFinanceiro =
            $"O valor total da locação será de {valorTotal}.\n\n" +
            "Condições de pagamento:\n" +
            $"- Entrada de {c.PercentualSinal}% equivalente a {valorSinal} no momento da assinatura do contrato.\n" +
            $"- Saldo restante pago até {dataLimite}, {diasTexto} antes da data do evento.\n\n" +
            "Os pagamentos deverão ser efetuados ao LOCADOR por meio de PIX para a chave: 15956325739";

        // Demais clausulas: texto custom (se houver) ou padrao, com placeholders aplicados.
        return
        [
            new ClausulaBase(TituloObjeto, TextoFinal(TituloObjeto, c)),
            new ClausulaBase(TituloFinanceiro, textoFinanceiro),
            new ClausulaBase(TituloResponsabilidades, TextoFinal(TituloResponsabilidades, c)),
            new ClausulaBase(TituloCancelamento, TextoFinal(TituloCancelamento, c)),
            new ClausulaBase(TituloForcaMaior, TextoFinal(TituloForcaMaior, c)),
            new ClausulaBase(TituloDisposicoesGerais, TextoFinal(TituloDisposicoesGerais, c)),
            new ClausulaBase(TituloResponsabilidadeLocador, TextoFinal(TituloResponsabilidadeLocador, c)),
            new ClausulaBase(TituloEnergia, TextoFinal(TituloEnergia, c))
        ];
    }

