public async Task<Result<Usuario>> Criar(string nome, string whatsApp, string? email = null, string? cpf = null)
    {
        if (string.IsNullOrWhiteSpace(nome))
            return Result.Fail<Usuario>("Nome é obrigatório.");

        if (string.IsNullOrWhiteSpace(whatsApp))
            return Result.Fail<Usuario>("WhatsApp é obrigatório.");

        var agora = DateTime.UtcNow;
        var usuario = new Usuario
        {
            Nome = nome.Trim(),
            WhatsApp = whatsApp.Trim(),
            Email = string.IsNullOrWhiteSpace(email) ? null : email.Trim(),
            Cpf = string.IsNullOrWhiteSpace(cpf) ? null : cpf.Trim(),
            CriadoEm = agora,
            AtualizadoEm = agora
        };

        db.Usuarios.Add(usuario);
        await db.SaveChangesAsync();

        return Result.Ok(usuario);
    }

