public async Task<Result> Editar(long id, string nome, string whatsApp, string? email = null, string? cpf = null)
    {
        if (string.IsNullOrWhiteSpace(nome))
            return Result.Fail("Nome é obrigatório.");

        if (string.IsNullOrWhiteSpace(whatsApp))
            return Result.Fail("WhatsApp é obrigatório.");

        var usuario = await db.Usuarios.FindAsync(id);
        if (usuario is null)
            return Result.Fail("Cliente não encontrado.");

        usuario.Nome = nome.Trim();
        usuario.WhatsApp = whatsApp.Trim();
        usuario.Email = string.IsNullOrWhiteSpace(email) ? null : email.Trim();
        usuario.Cpf = string.IsNullOrWhiteSpace(cpf) ? null : cpf.Trim();
        usuario.AtualizadoEm = DateTime.UtcNow;

        await db.SaveChangesAsync();

        return Result.Ok();
    }

