public async Task<List<Usuario>> BuscarPorNome(string termo)
    {
        if (string.IsNullOrWhiteSpace(termo) || termo.Trim().Length < 3)
            return [];

        var termoNormalizado = termo.Trim();
        return await db.Usuarios
            .Where(u => EF.Functions.Like(u.Nome, $"%{termoNormalizado}%"))
            .OrderBy(u => u.Nome)
            .Take(10)
            .ToListAsync();
    }

