using System.Text.Json;
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.Clientes.Services;
using EspacoLuaCheia.Web.Features.Contratos.Services;
using EspacoLuaCheia.Web.Features.Reservas.Services;
using EspacoLuaCheia.Web.Shared.Enums;
using Microsoft.EntityFrameworkCore;

public async Task<ResultadoComando> ExecutarAsync(JsonElement parametros)
    {
        // 1. Extrair campos obrigatórios
        if (!TryGetString(parametros, "nome_completo", out var nomeCompleto))
            return Falha("Campo 'nome_completo' é obrigatório.");

        if (!TryGetString(parametros, "whatsapp", out var whatsappRaw))
            return Falha("Campo 'whatsapp' é obrigatório.");

        if (!TryGetString(parametros, "cpf", out var cpfRaw))
            return Falha("Campo 'cpf' é obrigatório.");

        if (!TryGetString(parametros, "data_evento", out var dataEventoStr))
            return Falha("Campo 'data_evento' é obrigatório.");

        if (!TryGetString(parametros, "tipo_evento", out var tipoEventoStr))
            return Falha("Campo 'tipo_evento' é obrigatório.");

        if (!TryGetInt(parametros, "quantidade_convidados", out var qtdConvidados))
            return Falha("Campo 'quantidade_convidados' é obrigatório e deve ser um número inteiro.");

        if (!TryGetDecimal(parametros, "valor_total", out var valorTotal))
            return Falha("Campo 'valor_total' é obrigatório e deve ser um número decimal.");

        // 2. Normalizar CPF e WhatsApp
        var cpf = NormalizarDigitos(cpfRaw);
        var whatsapp = NormalizarDigitos(whatsappRaw);

        // 3. Parsear data
        if (!DateOnly.TryParseExact(dataEventoStr, "dd/MM/yyyy", out var dataEvento))
            return Falha($"Data do evento inválida: '{dataEventoStr}'. Use o formato dd/MM/yyyy (ex: 15/08/2026).");

        // 4. Parsear tipo de evento
        if (!Enum.TryParse<TipoEvento>(tipoEventoStr, ignoreCase: true, out var tipoEvento))
            return Falha($"Tipo de evento inválido: '{tipoEventoStr}'. Use 'Festa' ou 'Casamento'.");

        // 5. Campos opcionais
        TryGetString(parametros, "rg", out var rg);
        TryGetString(parametros, "email", out var email);
        TryGetString(parametros, "endereco", out var endereco);
        TryGetString(parametros, "horario_previsto", out var horarioPrevisto);
        TryGetInt(parametros, "percentual_sinal", out var percentualSinal);
        if (percentualSinal <= 0) percentualSinal = 50;

        await using var transaction = await db.Database.BeginTransactionAsync();
        try
        {
            // 6. Resolver cliente (criar ou reutilizar por WhatsApp)
            var usuarioExistente = await db.Usuarios
                .FirstOrDefaultAsync(u => u.WhatsApp == whatsapp);

            long usuarioId;
            string nomeUsuario;

            if (usuarioExistente is not null)
            {
                usuarioId = usuarioExistente.Id;
                nomeUsuario = usuarioExistente.Nome;

                // Atualizar email/cpf se fornecidos e diferentes
                var atualizado = false;
                if (!string.IsNullOrWhiteSpace(email) && usuarioExistente.Email != email)
                {
                    usuarioExistente.Email = email;
                    atualizado = true;
                }
                if (!string.IsNullOrWhiteSpace(cpf) && usuarioExistente.Cpf != cpf)
                {
                    usuarioExistente.Cpf = cpf;
                    atualizado = true;
                }
                if (atualizado)
                {
                    usuarioExistente.AtualizadoEm = DateTime.UtcNow;
                    await db.SaveChangesAsync();
                }
            }
            else
            {
                var resultCliente = await clienteService.Criar(nomeCompleto, whatsapp, email, cpf);
                if (!resultCliente.Sucesso)
                    return Falha($"Erro ao criar cliente: {resultCliente.Erro}");

                usuarioId = resultCliente.Valor!.Id;
                nomeUsuario = resultCliente.Valor.Nome;
            }

            // 7. Criar contrato
            var resultContrato = await contratoService.CriarPf(
                usuarioId: usuarioId,
                orcamentoId: null,
                nomeCompleto: nomeCompleto,
                rg: string.IsNullOrWhiteSpace(rg) ? null : rg,
                cpf: cpf,
                email: string.IsNullOrWhiteSpace(email) ? null : email,
                endereco: string.IsNullOrWhiteSpace(endereco) ? null : endereco,
                dataEvento: dataEvento,
                horarioPrevisto: string.IsNullOrWhiteSpace(horarioPrevisto) ? null : horarioPrevisto,
                horarioTermino: null,
                quantidadeConvidados: qtdConvidados,
                tipoEvento: tipoEvento,
                valorTotal: valorTotal,
                percentualSinal: percentualSinal);

            if (!resultContrato.Sucesso)
                return Falha($"Erro ao criar contrato: {resultContrato.Erro}");

            var contrato = resultContrato.Valor!;

            // 8. Criar reserva
            var resultReserva = await reservaService.CriarReserva(
                contratoId: contrato.Id,
                usuarioId: usuarioId,
                dataEvento: dataEvento,
                qtdConvidados: qtdConvidados,
                tipo: tipoEvento,
                valorTotal: valorTotal,
                percentualSinal: percentualSinal);

            if (!resultReserva.Sucesso)
                return Falha($"Erro ao criar reserva: {resultReserva.Erro}");

            var reserva = resultReserva.Valor!;

            await transaction.CommitAsync();

            return new ResultadoComando(
                Sucesso: true,
                MensagemParaModelo: $"Reserva criada com sucesso. ID da reserva: {reserva.Id}. " +
                                    $"ID do contrato: {contrato.Id}. " +
                                    $"Cliente: {nomeUsuario} (ID: {usuarioId}). " +
                                    $"Data do evento: {dataEvento:dd/MM/yyyy}. " +
                                    $"Tipo: {tipoEvento}. Convidados: {qtdConvidados}. " +
                                    $"Valor total: R$ {valorTotal:N2}.",
                MensagemUi: $"Reserva #{reserva.Id} criada com sucesso para {dataEvento:dd/MM/yyyy}.",
                DadosExtras: new { reservaId = reserva.Id, contratoId = contrato.Id, usuarioId }
            );
        }
        catch (Exception ex)
        {
            await transaction.RollbackAsync();
            return Falha($"Erro inesperado ao criar reserva: {ex.Message}");
        }
    }

