// File: Features/ChatAI/Services/ChatAIService.cs
// Namespace: EspacoLuaCheia.Web.Features.ChatAI.Services
// Class: ChatAIService
using System.Text.Json;
using EspacoLuaCheia.Web.Data;
using EspacoLuaCheia.Web.Features.ChatAI.Commands;
using EspacoLuaCheia.Web.Features.ChatAI.Dtos;
using EspacoLuaCheia.Web.Features.ChatAI.Entities;
using EspacoLuaCheia.Web.Features.ChatAI.Enums;
using Microsoft.EntityFrameworkCore;
using Microsoft.Extensions.Configuration;

// -------------------------------------------------------------------------
    // Processar uma mensagem dentro de uma sessão existente
    // -------------------------------------------------------------------------
    public async Task<MensagemChatDto> ProcessarMensagemAsync(
        long sessaoId,
        string textoUsuario,
        CancellationToken ct = default)
    {
        // 1. Salvar mensagem do usuário
        var msgUsuario = new MensagemChat
        {
            SessaoId = sessaoId,
            Remetente = RemetenteChat.Usuario,
            Conteudo = textoUsuario,
            CriadoEm = DateTime.UtcNow
        };
        db.MensagensChatAI.Add(msgUsuario);
        await db.SaveChangesAsync(ct);

        // 2. Carregar histórico
        var historico = await db.MensagensChatAI
            .Where(m => m.SessaoId == sessaoId)
            .OrderByDescending(m => m.Id)
            .Take(_maxMensagensHistorico)
            .OrderBy(m => m.Id)
            .ToListAsync(ct);

        // 3. Converter histórico para format OpenAI
        var messages = ConverterHistoricoParaOpenAi(historico);

        // 4. Montar system prompt
        var systemPrompt = MontarSystemPrompt();

        // 5. Primeira chamada ao LLM
        RespostaLlmDto resposta;
        try
        {
            resposta = await llmClient.EnviarAsync(messages, registry.Todos, systemPrompt, ct);
        }
        catch (TaskCanceledException)
        {
            return await SalvarMensagemSistema(sessaoId,
                "O modelo demorou demais para responder. Tente novamente.", ct);
        }
        catch (Exception ex)
        {
            return await SalvarMensagemSistema(sessaoId,
                $"Erro ao chamar o modelo: {ex.Message}", ct);
        }

        // 6. Resposta textual (sem tool call)
        if (!resposta.IsToolCall)
        {
            var msgAssistente = new MensagemChat
            {
                SessaoId = sessaoId,
                Remetente = RemetenteChat.Assistente,
                Conteudo = resposta.TextoResposta ?? string.Empty,
                CriadoEm = DateTime.UtcNow
            };
            db.MensagensChatAI.Add(msgAssistente);
            await db.SaveChangesAsync(ct);

            return ToDto(msgAssistente);
        }

        // 7. Tool call
        // 7a. Salvar o tool_call do assistente (com ToolCallJson para auditoria)
        var msgToolCall = new MensagemChat
        {
            SessaoId = sessaoId,
            Remetente = RemetenteChat.Assistente,
            Conteudo = string.Empty,
            ToolCallJson = resposta.TextoResposta, // raw JSON da tool_calls array
            CriadoEm = DateTime.UtcNow
        };
        db.MensagensChatAI.Add(msgToolCall);
        await db.SaveChangesAsync(ct);

        // 7b. Localizar comando
        var comando = registry.ObterPorNome(resposta.NomeTool!);
        if (comando is null)
        {
            return await SalvarMensagemSistema(sessaoId,
                $"Comando '{resposta.NomeTool}' não encontrado no sistema.", ct);
        }

        // 7c. Executar
        ResultadoComando resultado;
        try
        {
            resultado = await comando.ExecutarAsync(resposta.ParametrosTool!.Value);
        }
        catch (Exception ex)
        {
            resultado = new ResultadoComando(
                Sucesso: false,
                MensagemParaModelo: $"Erro inesperado durante execução: {ex.Message}");
        }

        // 7d. Salvar resultado da tool
        var toolResultJson = JsonSerializer.Serialize(new
        {
            sucesso = resultado.Sucesso,
            mensagem = resultado.MensagemParaModelo,
            dados = resultado.DadosExtras
        });

        var msgToolResult = new MensagemChat
        {
            SessaoId = sessaoId,
            Remetente = RemetenteChat.Sistema,
            Conteudo = resultado.MensagemParaModelo,
            ToolResultJson = toolResultJson,
            CriadoEm = DateTime.UtcNow
        };
        db.MensagensChatAI.Add(msgToolResult);
        await db.SaveChangesAsync(ct);

        // 7e. Segunda chamada — gerar resposta final em linguagem natural
        var historicoAtualizado = await db.MensagensChatAI
            .Where(m => m.SessaoId == sessaoId)
            .OrderByDescending(m => m.Id)
            .Take(_maxMensagensHistorico)
            .OrderBy(m => m.Id)
            .ToListAsync(ct);

        var messagesAtualizados = ConverterHistoricoParaOpenAi(historicoAtualizado,
            toolCallId: resposta.ToolCallId,
            nomeToolParaResult: resposta.NomeTool);

        RespostaLlmDto respostaFinal;
        try
        {
            respostaFinal = await llmClient.EnviarAsync(messagesAtualizados, registry.Todos, systemPrompt, ct);
        }
        catch (TaskCanceledException)
        {
            return await SalvarMensagemSistema(sessaoId,
                "O modelo demorou demais para responder após executar a ação. Tente novamente.", ct);
        }
        catch (Exception ex)
        {
            return await SalvarMensagemSistema(sessaoId,
                $"Ação executada, mas erro ao gerar confirmação: {ex.Message}", ct);
        }

        // 7f. Salvar resposta final
        var msgFinal = new MensagemChat
        {
            SessaoId = sessaoId,
            Remetente = RemetenteChat.Assistente,
            Conteudo = respostaFinal.TextoResposta ?? string.Empty,
            CriadoEm = DateTime.UtcNow
        };
        db.MensagensChatAI.Add(msgFinal);
        await db.SaveChangesAsync(ct);

        // Atualizar timestamp da sessão
        var sessao = await db.SessoesChatAI.FindAsync([sessaoId], ct);
        if (sessao is not null)
        {
            sessao.AtualizadoEm = DateTime.UtcNow;
            await db.SaveChangesAsync(ct);
        }

        return ToDto(msgFinal, resultado.MensagemUi, resultado.Sucesso);
    }

