private static bool? ParseSucessoFromToolResult(string? toolResultJson)
    {
        if (string.IsNullOrEmpty(toolResultJson)) return null;
        try
        {
            using var doc = JsonDocument.Parse(toolResultJson);
            if (doc.RootElement.TryGetProperty("sucesso", out var v) && v.ValueKind == JsonValueKind.True)
                return true;
            if (v.ValueKind == JsonValueKind.False)
                return false;
        }
        catch { /* JSON inválido — ignorar */ }
        return null;
    }

