// File: Features/ChatAI/Services/LlmApiClient.cs
// Namespace: EspacoLuaCheia.Web.Features.ChatAI.Services
// Class: LlmApiClient
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using EspacoLuaCheia.Web.Features.ChatAI.Commands;
using EspacoLuaCheia.Web.Features.ChatAI.Dtos;
using Microsoft.Extensions.Configuration;

public async Task<RespostaLlmDto> EnviarAsync(
        List<object> messages,
        IReadOnlyCollection<IChatCommand> tools,
        string systemPrompt,
        CancellationToken cancellationToken = default)
    {
        var toolsPayload = tools.Select(t => new
        {
            type = "function",
            function = new
            {
                name = t.NomeTool,
                description = t.Descricao,
                parameters = t.ParametrosSchema
            }
        }).ToList();

        var allMessages = new List<object>
        {
            new { role = "system", content = systemPrompt }
        };
        allMessages.AddRange(messages);

        var payload = new
        {
            model = _modelName,
            max_tokens = _maxTokens,
            temperature = _temperature,
            messages = allMessages,
            tools = toolsPayload.Count > 0 ? toolsPayload : null,
            tool_choice = toolsPayload.Count > 0 ? "auto" : null
        };

        var response = await _http.PostAsJsonAsync("chat/completions", payload, SerializerOptions, cancellationToken);
        response.EnsureSuccessStatusCode();

        using var doc = await response.Content.ReadFromJsonAsync<JsonDocument>(cancellationToken: cancellationToken)
            ?? throw new InvalidOperationException("Resposta vazia do modelo.");

        var choice = doc.RootElement
            .GetProperty("choices")[0];

        var finishReason = choice.GetProperty("finish_reason").GetString();
        var message = choice.GetProperty("message");

        if (finishReason == "tool_calls" && message.TryGetProperty("tool_calls", out var toolCallsEl))
        {
            var toolCall = toolCallsEl[0];
            var toolCallId = toolCall.GetProperty("id").GetString()!;
            var functionEl = toolCall.GetProperty("function");
            var nomeTool = functionEl.GetProperty("name").GetString()!;
            var argumentsJson = functionEl.GetProperty("arguments").GetString()!;

            using var argsDoc = JsonDocument.Parse(argumentsJson);

            // Persist raw tool_call JSON for auditing
            var toolCallJson = toolCallsEl.GetRawText();

            return new RespostaLlmDto
            {
                IsToolCall = true,
                NomeTool = nomeTool,
                ParametrosTool = argsDoc.RootElement.Clone(),
                ToolCallId = toolCallId,
                TextoResposta = toolCallJson // stored for audit in ToolCallJson field
            };
        }

        var content = message.TryGetProperty("content", out var contentEl)
            ? contentEl.GetString() ?? string.Empty
            : string.Empty;

        return new RespostaLlmDto
        {
            IsToolCall = false,
            TextoResposta = content
        };
    }

