using EspacoLuaCheia.Web.Features.TabelaPrecos.Entities;
using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.Metadata.Builders;

public class TabelaPrecoConfiguration : IEntityTypeConfiguration<TabelaPreco>
{
    public void Configure(EntityTypeBuilder<TabelaPreco> builder)
    {
        builder.HasKey(t => t.Id);

        builder.Property(t => t.Id)
            .ValueGeneratedOnAdd();

        builder.Property(t => t.Nome)
            .IsRequired()
            .HasMaxLength(200);

        builder.Property(t => t.TipoEvento)
            .IsRequired()
            .HasConversion<int>();

        builder.Property(t => t.VigenciaInicio)
            .IsRequired();

        builder.Property(t => t.VigenciaFim)
            .IsRequired();

        builder.Property(t => t.PercentualSinal)
            .IsRequired();

        builder.Property(t => t.DiasAntecedenciaSaldo)
            .IsRequired();

        builder.Property(t => t.Descricao)
            .HasMaxLength(500);

        builder.Property(t => t.Ativa)
            .IsRequired();

        builder.Property(t => t.CriadoEm)
            .IsRequired();

        builder.Property(t => t.AtualizadoEm)
            .IsRequired();

        builder.HasIndex(t => new { t.TipoEvento, t.VigenciaInicio, t.VigenciaFim });

        // Within-context navigation: TabelaPreco -> FaixaPreco
        builder.HasMany(t => t.Faixas)
            .WithOne(f => f.TabelaPreco)
            .HasForeignKey(f => f.TabelaPrecoId)
            .OnDelete(DeleteBehavior.Cascade);

        // Within-context navigation: TabelaPreco -> OpcaoSuite
        builder.HasMany(t => t.OpcoesSuite)
            .WithOne(o => o.TabelaPreco)
            .HasForeignKey(o => o.TabelaPrecoId)
            .OnDelete(DeleteBehavior.Cascade);
    }
}

